struct TwoSet {
	// priority_queue 比 multiset 更快
	priority_queue<int> l;
	priority_queue<int, vector<int>, greater<int>> r;
	int len = 0;
	void insert(int x) {
		len++;
		if (l.empty() or x <= l.top())l.push(x);
		else r.push(x);
		int mid = (len + 1) / 2;
		while (l.size() > mid) {
			r.push(l.top());
			l.pop();
		}
		while (l.size() < mid) {
			l.push(r.top());
			r.pop();
		}
	}
	int get() {
		if (len == 0)return -1;
		return l.top();
	}
};
void solve(int CASE)
{
	int n; cin >> n;
	var a = vector<int>(n + 1);
	var b = vector<int>();
	fa(i, 1, n)cin >> a[i], b.pb(a[i]);
	sort(all(b));
	b.erase(unique(all(b)), b.end());
	var find = [&](int x)->int {
		return upper_bound(all(b), x) - b.begin();
		};
	int m = b.size();
	fa(i, 1, n)a[i] = find(a[i]);
	var dp = Vec2<int>(n + 1, m + 1, -1);
	fa(i, 1, m)dp[0][i] = 0;
	fa(i, 1, n) {
		var se = TwoSet();
		int len = 0;
		fb(j, i, 1) {
			len++;
			se.insert(a[j]);
			if (len % 2 == 0)continue;
			int now = se.get();
			if (dp[j - 1][now] != -1)
				dp[i][now] = max(dp[i][now], dp[j - 1][now] + 1);
		}
	}
	int ans = 0;
	fa(i, 1, m)ans = max(ans, dp[n][i]);
	cout << ans << endl;
	return;
}
